/// Configure all HTTP routes for this module using Axum and BackboneCrudHandler.
///
/// Each entity gets 12 standard Backbone CRUD endpoints:
/// 1. GET /api/v1/{collection} - List with pagination
/// 2. POST /api/v1/{collection} - Create
/// 3. GET /api/v1/{collection}/:id - Get by ID
/// 4. PUT /api/v1/{collection}/:id - Full update
/// 5. PATCH /api/v1/{collection}/:id - Partial update
/// 6. DELETE /api/v1/{collection}/:id - Soft delete
/// 7. POST /api/v1/{collection}/bulk - Bulk create
/// 8. POST /api/v1/{collection}/upsert - Upsert
/// 9. GET /api/v1/{collection}/trash - List deleted
/// 10. POST /api/v1/{collection}/:id/restore - Restore
/// 11. DELETE /api/v1/{collection}/empty - Empty trash
/// 12. GET /api/v1/{collection}/:id/deleted - Get deleted by ID
pub fn configure_routes(services: HttpServices) -> Router {
    Router::new()
        // AgentEarning routes (12 Backbone endpoints)
        .merge(create_agent_earning_routes(services.agent_earning))
        // FinancialPeriod routes (12 Backbone endpoints)
        .merge(create_financial_period_routes(services.financial_period))
        // Payment routes (12 Backbone endpoints)
        .merge(create_payment_routes(services.payment))
        // PaymentGatewayDetail routes (12 Backbone endpoints)
        .merge(create_payment_gateway_detail_routes(services.payment_gateway_detail))
        // PaymentFee routes (12 Backbone endpoints)
        .merge(create_payment_fee_routes(services.payment_fee))
        // Invoice routes (12 Backbone endpoints)
        .merge(create_invoice_routes(services.invoice))
        // InvoiceParty routes (12 Backbone endpoints)
        .merge(create_invoice_party_routes(services.invoice_party))
        // InvoiceLineItem routes (12 Backbone endpoints)
        .merge(create_invoice_line_item_routes(services.invoice_line_item))
        // ProviderBankAccount routes (12 Backbone endpoints)
        .merge(create_provider_bank_account_routes(services.provider_bank_account))
        // RefundRequest routes (12 Backbone endpoints)
        .merge(create_refund_request_routes(services.refund_request))
        // Settlement routes (12 Backbone endpoints)
        .merge(create_settlement_routes(services.settlement))
}

